insert into login_bonus_message_data values (1, 60000, 1, 0, 0, 1, 190804, '花凛', '新年来临，要不要用抽签\\n来占卜一下新一天的运势呢？\\n运势越好，\\n越能获得大量的礼物哦♪', 1, 0, '');
insert into login_bonus_message_data values (2, 60000, 2, 0, 1, 1, 0, '', '今日运势是姬吉！所有方面的运气都是最好的！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000现在的你甚至可以征服「传说中的吸血鬼」，称霸世界也不是梦！', 0, 0, '');
insert into login_bonus_message_data values (3, 60000, 2, 0, 1, 1, 0, '', '今日运势是姬吉！做什么都很顺利！超棒的对吧☆\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000幸运物品是饭团！能吃得饱饱的，继续幸福下去！', 0, 0, '');
insert into login_bonus_message_data values (4, 60000, 2, 0, 1, 2, 0, '', '今日运势是姬吉！运气如将军般势不可挡！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000众人将拜倒在你的威光之下，你就是最受欢迎的人！', 0, 0, '');
insert into login_bonus_message_data values (5, 60000, 2, 0, 2, 1, 0, '', '今日运势是大吉！运气逐渐高涨！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000不管做什么，都能事半功倍♪', 0, 0, '');
insert into login_bonus_message_data values (6, 60000, 2, 0, 2, 1, 0, '', '今日运势是大吉！不管做什么都会很顺利，很引人注目！\u3000\u3000\u3000\u3000\u3000身后或许有人正看着如此出色的你哦……嘻嘻♪', 0, 0, '');
insert into login_bonus_message_data values (7, 60000, 2, 0, 2, 2, 0, '', '今日运势是大吉！运气很好，不管挑战什么都能成功！\u3000\u3000\u3000\u3000\u3000\u3000似乎能发挥出隐藏的才能！向着秀菜……不，秀才前进吧！', 0, 0, '');
insert into login_bonus_message_data values (8, 60000, 2, 0, 3, 1, 0, '', '今日运势是中吉！交易运提升！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000幸运物品是鲷鱼烧！日式点心的力量可以提高销售额！', 0, 0, '');
insert into login_bonus_message_data values (9, 60000, 2, 0, 3, 1, 0, '', '今日运势是中吉！旅行运大幅上升中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000 说不定还能去往「真步真步王国」呢♪', 0, 0, '');
insert into login_bonus_message_data values (10, 60000, 2, 0, 3, 1, 0, '', '今日运势是中吉！事业运急速上升！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000你一定会像「飞舞于炼狱的一阵疾风」一般活跃的！', 0, 0, '');
insert into login_bonus_message_data values (11, 60000, 2, 0, 3, 1, 0, '', '今日运势是中吉！静待良机就会有好结果！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000幸运物品是布丁，吃掉它招来好运吧！', 0, 0, '');
insert into login_bonus_message_data values (12, 60000, 2, 0, 3, 2, 0, '', '今日运势是中吉！运气稳步上升！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000今天的你如有精灵加护，许多事情都会顺利起来♪', 0, 0, '');
insert into login_bonus_message_data values (13, 60000, 2, 0, 4, 1, 0, '', '今日运势是小吉！一早就有幸运的征兆！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000说不定会有温柔的姐姐叫你起床哦♪', 0, 0, '');
insert into login_bonus_message_data values (14, 60000, 2, 0, 4, 1, 0, '', '今日运势是小吉！运气虽然在上升，但是上升期间要小心！\u3000\u3000\u3000\u3000幸运动物是熊！或许它会像真正的家人一样守护你♪', 0, 0, '');
insert into login_bonus_message_data values (15, 60000, 2, 0, 4, 1, 0, '', '今日运势是小吉！外出悠闲度日可以提升运气！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000幸运地是牧场。说不定会有段有趣的邂逅♪', 0, 0, '');
insert into login_bonus_message_data values (16, 60000, 2, 0, 4, 1, 0, '', '今日运势是小吉！运气很好，但要小心突发事件！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000出门可能会被当成「可疑人物」……', 0, 0, '');
insert into login_bonus_message_data values (17, 60000, 2, 0, 4, 2, 0, '', '今日运势是小吉！不要太拼命，放松一点就能获得好运！\u3000\u3000\u3000\u3000\u3000幸运人物是偶像。歌曲能给你带来幸福♪', 0, 0, '');
insert into login_bonus_message_data values (18, 60000, 3, 0, 0, 0, 190804, '花凛', '抽签结果如何？\\n希望对你来说\\n新的一天会是美好的一天\\n明天再来玩哦♪', 2, 0, '');
insert into login_bonus_message_data values (19, 60000, 3, 7, 0, 0, 190804, '花凛', '抽签玩得开心吗？\\n真心祝福你\\n希望新的一年对你来说\\n是美好的一年', 3, 0, '');
insert into login_bonus_message_data values (20, 80001, 0, 1, 0, 0, 101201, '初音', '和你相遇，\\n都已经过了一年了呢！\\n嗯～我一直都在睡觉，', 1, 0, '');
insert into login_bonus_message_data values (21, 80001, 0, 1, 0, 0, 101201, '初音', '所以希望能稍微\\n减少一点睡眠时间，\\n增加和你在一起的时间♪', 2, 0, '');
insert into login_bonus_message_data values (22, 80001, 1, 1, 0, 0, 103801, '栞', '认识你已经一年了……\\n时间过得真快啊。', 1, 0, '');
insert into login_bonus_message_data values (23, 80001, 1, 1, 0, 0, 103801, '栞', '要是明年也能\\n和你在一起……\\n我会很开心的。', 2, 0, '');
insert into login_bonus_message_data values (24, 80001, 0, 2, 0, 0, 103601, '镜华', '和你在一起，\\n已经一年了啊……', 1, 0, '');
insert into login_bonus_message_data values (25, 80001, 0, 2, 0, 0, 103601, '镜华', '你比刚开始的时候\\n要可靠多了呢。\\n我呢？有成长吗？', 2, 0, '');
insert into login_bonus_message_data values (26, 80001, 1, 2, 0, 0, 102001, '美美', '和哥哥相遇，\\n已经一年了！', 1, 0, '');
insert into login_bonus_message_data values (27, 80001, 1, 2, 0, 0, 102001, '美美', '美美和哥哥去了好多地方玩，\\n好开心♪今后你也要\\n一直陪着美美哦！', 2, 0, '');
insert into login_bonus_message_data values (28, 80001, 2, 2, 0, 0, 100401, '未奏希', '哥哥被未奏希的恶作剧捉弄，\\n已经有一年了啊。', 1, 0, '');
insert into login_bonus_message_data values (29, 80001, 2, 2, 0, 0, 100401, '未奏希', '今后……\\n也要经常和未奏希玩哦，\\n哥哥！', 2, 0, '');
insert into login_bonus_message_data values (30, 80001, 0, 3, 0, 0, 101001, '真步', '和王子相遇\\n好像已经有一年了呢。\\n时间真快呀。', 1, 0, '');
insert into login_bonus_message_data values (31, 80001, 0, 3, 0, 0, 101001, '真步', '这样下去，我很快就会变成\\n干巴巴的老婆婆吧。\\n开玩笑的。呵呵。', 2, 0, '');
insert into login_bonus_message_data values (32, 80001, 1, 3, 0, 0, 104401, '伊莉亚', '和汝相遇已经一年了啊，\\n今后还要尽心伺候我才是。', 1, 0, '');
insert into login_bonus_message_data values (33, 80001, 1, 3, 0, 0, 104401, '伊莉亚', '妾身偶尔也要\\n回报一下汝做出的贡献呢♪', 2, 0, '');
insert into login_bonus_message_data values (34, 80001, 2, 3, 0, 0, 101701, '香织', '和你相遇，\\n已经过了很长一段时间了～\\n不过，我们的旅程才刚刚开始！', 1, 0, '');
insert into login_bonus_message_data values (35, 80001, 2, 3, 0, 0, 101701, '香织', '今后也请\\n多多指教～', 2, 0, '');
insert into login_bonus_message_data values (36, 80001, 0, 4, 0, 0, 102801, '咲恋', '和你相遇\\n已经过了这么久了啊～', 1, 0, '');
insert into login_bonus_message_data values (37, 80001, 0, 4, 0, 0, 102801, '咲恋', '欢乐的时光总是\\n转眼即逝！\\n今后也一起加油吧！', 2, 0, '');
insert into login_bonus_message_data values (38, 80001, 1, 4, 0, 0, 102501, '铃莓', '我们相遇已经一年了，\\n我一直在给你添麻烦，\\n真是抱歉……', 1, 0, '');
insert into login_bonus_message_data values (39, 80001, 1, 4, 0, 0, 102501, '铃莓', '今后我会更加努力的，你要注视着我哦。\\n如果可以的话……\\n希望你能靠得更近一点♪', 2, 0, '');
insert into login_bonus_message_data values (40, 80001, 0, 5, 0, 0, 104601, '珠希', '回想一下，至今为止发生了\\n好多事情喵……', 1, 0, '');
insert into login_bonus_message_data values (41, 80001, 0, 5, 0, 0, 104601, '珠希', '今后我们两人也要\\n创造许许多多的回忆喵！', 2, 0, '');
insert into login_bonus_message_data values (42, 80001, 1, 5, 0, 0, 104801, '美冬', '和你结为师徒，\\n也已经一年了……\\n可是我还有很多要教你的东西。', 1, 0, '');
insert into login_bonus_message_data values (43, 80001, 1, 5, 0, 0, 104801, '美冬', '今后，\\n也要认真跟着我学习哦！', 2, 0, '');
insert into login_bonus_message_data values (44, 80001, 0, 6, 0, 0, 103201, '秋乃', '和你相遇已经一年了……', 1, 0, '');
insert into login_bonus_message_data values (45, 80001, 0, 6, 0, 0, 103201, '秋乃', '俗话说，光阴似箭……\\n回忆是金钱\\n永远也买不来的。', 2, 0, '');
insert into login_bonus_message_data values (46, 80001, 1, 6, 0, 0, 103401, '由加莉', '一年来，\\n你一直照顾着不成器的我，\\n真的非常感谢。', 1, 0, '');
insert into login_bonus_message_data values (47, 80001, 1, 6, 0, 0, 103401, '由加莉', '虽然我还有很多不足的地方，\\n但如果今后你还愿意陪在我身边，\\n我会很开心的。', 2, 0, '');
insert into login_bonus_message_data values (48, 80001, 0, 7, 0, 0, 107101, '克莉丝提娜', '和你相遇已经一年了啊。\\n没想到你竟然成了\\n我的结婚对象……', 1, 0, '');
insert into login_bonus_message_data values (49, 80001, 0, 7, 0, 0, 107101, '克莉丝提娜', '总之，今后\\n你也要好好取悦我哦☆', 2, 0, '');
insert into login_bonus_message_data values (50, 80001, 1, 7, 0, 0, 104701, '纯', '和你相遇已经一年了啊。\\n和过去相比，我的表情似乎也变得\\n柔和了许多，你觉得呢？', 1, 0, '');
insert into login_bonus_message_data values (51, 80001, 1, 7, 0, 0, 104701, '纯', '看不见，所以你也不确定？\\n这倒也是……', 2, 0, '');
insert into login_bonus_message_data values (52, 80001, 0, 8, 0, 0, 103701, '智', '已经过去一年了呢。\\n捉弄你的这段日子\\n还是很愉快的♪', 1, 0, '');
insert into login_bonus_message_data values (53, 80001, 0, 8, 0, 0, 103701, '智', '今后也请多多指教啦！', 2, 0, '');
insert into login_bonus_message_data values (54, 80001, 1, 8, 0, 0, 100501, '茉莉', '我们相遇已经\\n一年啦。真是想象不到呀。', 1, 0, '');
insert into login_bonus_message_data values (55, 80001, 1, 8, 0, 0, 100501, '茉莉', '每天都很开心，\\n时间好像很快就过去了。\\n今后也一起和恶势力战斗吧！', 2, 0, '');
insert into login_bonus_message_data values (56, 80001, 0, 9, 0, 0, 100701, '宫子', '和你相遇已经一年了！\\n虽然我没能成佛，', 1, 0, '');
insert into login_bonus_message_data values (57, 80001, 0, 9, 0, 0, 100701, '宫子', '也没有复活，但非常开心♪\\n只要有你和布丁在，\\n宫子就是快乐的♪', 2, 0, '');
insert into login_bonus_message_data values (58, 80001, 1, 9, 0, 0, 103101, '忍', '和你相遇已经一年了呢。\\n不过，根据我的占卜来看，', 1, 0, '');
insert into login_bonus_message_data values (59, 80001, 1, 9, 0, 0, 103101, '忍', '明年也好，后年也好，\\n我们都会一直在一起的。\\n呵呵，请多指教了。', 2, 0, '');
insert into login_bonus_message_data values (60, 80001, 0, 10, 0, 0, 100901, '杏奈', '你以闪光的吉格鲁特这一身份觉醒\\n已经一年了啊……虽然今后\\n我们长久的战斗不会结束，', 1, 0, '');
insert into login_bonus_message_data values (61, 80001, 0, 10, 0, 0, 100901, '杏奈', '但和你在一起的话……\\n我已经准备好与你白头偕老了！', 2, 0, '');
insert into login_bonus_message_data values (62, 80001, 1, 10, 0, 0, 101301, '七七香', '和你相遇已经一年了！\\n好快呀——', 1, 0, '');
insert into login_bonus_message_data values (63, 80001, 1, 10, 0, 0, 101301, '七七香', '今后我们也会是最强的二人组，\\n并且继续活跃下去！\\n靠你了哦，我的好搭档！', 2, 0, '');
insert into login_bonus_message_data values (64, 80001, 0, 11, 0, 0, 105101, '深月', '一年真是转瞬即逝啊。\\n我对你还有很多\\n不了解的地方……', 1, 0, '');
insert into login_bonus_message_data values (65, 80001, 0, 11, 0, 0, 105101, '深月', '今后也让我\\n仔细地调查你吧？', 2, 0, '');
insert into login_bonus_message_data values (66, 80001, 1, 11, 0, 0, 105601, '流夏', '和你相遇已经一年了啊。\\n本来是想助你一臂之力的。', 1, 0, '');
insert into login_bonus_message_data values (67, 80001, 1, 11, 0, 0, 105601, '流夏', '没想到却总是让你来帮我呢，\\n今后也请多指教！', 2, 0, '');
insert into login_bonus_message_data values (68, 80001, 2, 11, 0, 0, 102701, '惠理子', '时间真快啊，\\n和您相遇已经一年了……', 1, 0, '');
insert into login_bonus_message_data values (69, 80001, 2, 11, 0, 0, 102701, '惠理子', '和您在一起，时光转瞬即逝。\\n必须要研究让时间停止的方法\\n才行了……', 2, 0, '');
insert into login_bonus_message_data values (70, 80001, 0, 12, 0, 0, 102301, '绫音', '和哥哥相遇，\\n已经有一年了呢。\\n我有没有变得像大姐姐一点呢？', 1, 0, '');
insert into login_bonus_message_data values (71, 80001, 0, 12, 0, 0, 102301, '绫音', '啊，噗吉也变得\\n像大哥哥了对吧？', 2, 0, '');
insert into login_bonus_message_data values (72, 80001, 1, 12, 0, 0, 104201, '千歌', '和你相遇，\\n已经有一年了啊……\\n今后也请你陪在我身旁守护我，', 1, 0, '');
insert into login_bonus_message_data values (73, 80001, 1, 12, 0, 0, 104201, '千歌', '如果可以的话，\\n希望永远都这样下去……', 2, 0, '');
insert into login_bonus_message_data values (74, 80001, 2, 12, 0, 0, 102101, '胡桃', '和哥哥相遇已经一年了啊。\\n我还是老样子，什么都不行……', 1, 0, '');
insert into login_bonus_message_data values (75, 80001, 2, 12, 0, 0, 102101, '胡桃', '但、但是今后……\\n我也想和哥哥一直在一起……', 2, 0, '');
insert into login_bonus_message_data values (76, 80001, 0, 13, 0, 0, 104901, '静流', '再会之后已经过去一年，\\n我特意做了料理来庆祝♪\\n特制蛋糕、寿司、', 1, 0, '');
insert into login_bonus_message_data values (77, 80001, 0, 13, 0, 0, 104901, '静流', '汉堡肉、咖喱、炖菜，啊，\\n这无法隐藏的佐料香气\\n是姐姐的爱意哦！', 2, 0, '');
insert into login_bonus_message_data values (78, 80001, 1, 13, 0, 0, 101101, '璃乃', '和哥哥重逢，\\n已经有一年了呢。\\n回想起见不到你的日子，', 1, 0, '');
insert into login_bonus_message_data values (79, 80001, 1, 13, 0, 0, 101101, '璃乃', '今年真是\\n幸福得难以置信的一年！你再也不准\\n离开我身边了哦♪', 2, 0, '');
insert into login_bonus_message_data values (80, 80001, 0, 14, 0, 0, 100201, '优衣', '和骑士君从相遇到现在，\\n发生了很多事呢。\\n快乐的事，让人心跳加速的事……', 1, 0, '');
insert into login_bonus_message_data values (81, 80001, 0, 14, 0, 0, 100201, '优衣', '今后，我、我也想\\n一直和你……\\n度过这样的每一天！', 2, 0, '');
insert into login_bonus_message_data values (82, 80001, 1, 14, 0, 0, 100101, '日和莉', '和骑士先生相遇，\\n只过了一年而已吗！？', 1, 0, '');
insert into login_bonus_message_data values (83, 80001, 1, 14, 0, 0, 100101, '日和莉', '总觉得好像一直和你在一起……诶嘿嘿。\\n接下来的一年也请多指教了！\\n骑士先生！', 2, 0, '');
insert into login_bonus_message_data values (84, 80001, 2, 14, 0, 0, 100301, '怜', '距离和你初次相遇，已经一年了……\\n我们都变了很多，\\n变得更强了……', 1, 0, '');
insert into login_bonus_message_data values (85, 80001, 2, 14, 0, 0, 100301, '怜', '希望我能尽早\\n将后背交付给你。', 2, 0, '');
insert into login_bonus_message_data values (86, 80001, 0, 15, 0, 0, 105801, '佩可莉姆', '谢谢你\\n这一年来一直没有忘记我！', 1, 0, '');
insert into login_bonus_message_data values (87, 80001, 0, 15, 0, 0, 105801, '佩可莉姆', '今后也请你\\n永远记住我哦！', 2, 0, '');
insert into login_bonus_message_data values (88, 80001, 1, 15, 0, 0, 105901, '可可萝', '这一年来，能陪伴在主人身边，\\n我觉得非常光荣。\\n希望今后，', 1, 0, '');
insert into login_bonus_message_data values (89, 80001, 1, 15, 0, 0, 105901, '可可萝', '也能永远照顾主人。\\n我想要永远\\n当主人的引导者。', 2, 0, '');
insert into login_bonus_message_data values (90, 80001, 2, 15, 0, 0, 106001, '凯露', '一年啊，\\n没想到和你相处了这么长时间～\\n不过……这一年还挺愉快的。', 1, 0, '');
insert into login_bonus_message_data values (91, 80001, 2, 15, 0, 0, 106001, '凯露', '所以，我还会再\\n和你相处一段时间的，\\n你应该高兴才是！', 2, 0, '');
insert into login_bonus_message_data values (92, 60001, 1, 0, 0, 1, 112101, '铃莓', '新年伊始，\\n抽个签如何？\\n运势越好，\\n就能获得越多礼物哦♪', 1, 0, '');
insert into login_bonus_message_data values (93, 60001, 2, 0, 1, 1, 0, '', '今日运势是姬吉！\u3000所有方面的运气都是最好的！\u3000\u3000\u3000从现在开始跟随“传说中的吸血鬼”，哪怕征服世界也不是梦！', 0, 0, '');
insert into login_bonus_message_data values (94, 60001, 2, 0, 1, 1, 0, '', '今日运势是姬吉！\u3000所做的一切都到达了最高峰！\u3000真棒啊☆幸运道具是饭团！\u3000吃饱喝足之后，幸福也会持续吧！', 0, 0, '');
insert into login_bonus_message_data values (95, 60001, 2, 0, 1, 1, 0, '', '今日运势是姬吉！\u3000用最强的运气规避所有失败吧！\u3000一定能和重要的人一起度过最棒的一天！', 0, 0, '');
insert into login_bonus_message_data values (96, 60001, 2, 0, 1, 1, 0, '', '今日运势是姬吉！\u3000无论什么挑战都能顺利应对，是最棒的运势！这正是能变为理想中的自己的绝佳机会！\u3000踏出新的一步吧！', 0, 0, '');
insert into login_bonus_message_data values (97, 60001, 2, 0, 1, 2, 0, '', '今日运势是姬吉！\u3000运气如将军般势不可挡！\u3000众人都拜倒于你的威光之下，你就是最受欢迎的人！', 0, 0, '');
insert into login_bonus_message_data values (98, 60001, 2, 0, 2, 1, 0, '', '今日运势是大吉！\u3000运气逐渐高涨！\u3000\u3000\u3000\u3000\u3000不管做什么，都能以最高效率获得非常棒的结果♪', 0, 0, '');
insert into login_bonus_message_data values (99, 60001, 2, 0, 2, 1, 0, '', '今日运势是大吉！\u3000不管做什么都会顺利，大显身手！\u3000\u3000\u3000身后正有人看着如此出色的你哦……嘻嘻♪', 0, 0, '');
insert into login_bonus_message_data values (100, 60001, 2, 0, 2, 1, 0, '', '今日运势是大吉！\u3000幸运词是“切噜♪”\u3000\u3000\u3000\u3000和见到的所有人说这句话，会变得快乐哦！', 0, 0, '');
insert into login_bonus_message_data values (101, 60001, 2, 0, 2, 1, 0, '', '今日运势是大吉！\u3000这运势简直完美无敌！\u3000\u3000\u3000\u3000\u3000\u3000\u3000用龙之眼看穿一切，度过预想之中的一天吧！', 0, 0, '');
insert into login_bonus_message_data values (102, 60001, 2, 0, 2, 2, 0, '', '今日运势是大吉！\u3000运气很好，无论挑战什么都有好结果！似乎还能激发隐藏的才能！\u3000目标是成为修……不对，是秀才！', 0, 0, '');
insert into login_bonus_message_data values (103, 60001, 2, 0, 3, 1, 0, '', '今日运势是中吉！\u3000会生意兴隆！\u3000\u3000\u3000\u3000\u3000\u3000\u3000幸运道具是鲷鱼烧！和果子之力让营业额上涨了！', 0, 0, '');
insert into login_bonus_message_data values (104, 60001, 2, 0, 3, 1, 0, '', '今日运势是中吉！\u3000旅行运迅速上升中♪\u3000\u3000\u3000\u3000\u3000\u3000\u3000说不定还能去那个“真步真步王国”呢♪', 0, 0, '');
insert into login_bonus_message_data values (105, 60001, 2, 0, 3, 1, 0, '', '今日运势是中吉！\u3000工作运急速上升中！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000肯定会像“刮过地狱的一阵疾风”那般活跃！', 0, 0, '');
insert into login_bonus_message_data values (106, 60001, 2, 0, 3, 1, 0, '', '今日运势是中吉！\u3000等候机会就能有好的结果！\u3000\u3000\u3000\u3000\u3000\u3000品尝幸运道具布丁，召唤运气吧！', 0, 0, '');
insert into login_bonus_message_data values (107, 60001, 2, 0, 3, 1, 0, '', '今日运势是中吉！\u3000在外出的地点应该会有良缘降临！\u3000也许会有消极系的聪明姑娘给你甜甜～的糖哦？', 0, 0, '');
insert into login_bonus_message_data values (108, 60001, 2, 0, 3, 1, 0, '', '今日运势是中吉！\u3000只要强行推进，就能搞定大部分的事！幸运地点是游戏中心。用拳击游戏机缓解压力！', 0, 0, '');
insert into login_bonus_message_data values (109, 60001, 2, 0, 3, 2, 0, '', '今日运势是中吉！\u3000运气逐渐上升！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000有如受到精灵的加护一般，许多事情都会顺利起来♪', 0, 0, '');
insert into login_bonus_message_data values (110, 60001, 2, 0, 4, 1, 0, '', '今日运势是小吉！\u3000一大早就有幸运的征兆！\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000\u3000说不定会有温柔的姐姐叫醒你哦♪', 0, 0, '');
insert into login_bonus_message_data values (111, 60001, 2, 0, 4, 1, 0, '', '今日运势是小吉！\u3000虽然运气在上升，但在上升之前要小心！\u3000幸运动物是熊！\u3000可能会像真正的家人那样守护你♪', 0, 0, '');
insert into login_bonus_message_data values (112, 60001, 2, 0, 4, 1, 0, '', '今日运势是小吉！\u3000在室外悠闲度过的话，运气就会上升！\u3000\u3000幸运地点是牧场。好像会发生有趣的相遇♪', 0, 0, '');
insert into login_bonus_message_data values (113, 60001, 2, 0, 4, 1, 0, '', '今日运势是小吉！\u3000运气很好，但要注意突发事件！\u3000可能会在外出的地方被当成「可疑人物」……', 0, 0, '');
insert into login_bonus_message_data values (114, 60001, 2, 0, 4, 1, 0, '', '今日运势是小吉！\u3000或许能找到志同道合的好友哦！\u3000\u3000\u3000\u3000关键词是“小由仁”，牢记于心吧！', 0, 0, '');
insert into login_bonus_message_data values (115, 60001, 2, 0, 4, 1, 0, '', '今日运势是小吉！\u3000也许会和意想不到的对象成为朋友？\u3000\u3000\u3000\u3000\u3000注意不要一不小心就挖苦别人！', 0, 0, '');
insert into login_bonus_message_data values (116, 60001, 2, 0, 4, 2, 0, '', '今日运势是小吉！\u3000不要逼迫自己，放松下来运气就会变好！\u3000幸运人物是偶像。歌声会让你幸福♪', 0, 0, '');
insert into login_bonus_message_data values (117, 60001, 3, 0, 0, 0, 112101, '铃莓', '抽签结果如何？\\n希望对你来说，新的一天\\n会是美好的一天，\\n明天要再来玩哦♪', 2, 0, '');
insert into login_bonus_message_data values (118, 60001, 3, 7, 0, 0, 112101, '铃莓', '抽签玩得开心吗？\\n真心祝福你，希望\\n新的一年对你来说\\n是美好的一年', 3, 0, '');
insert into login_bonus_message_data values (119, 80003, 0, 1, 0, 0, 105801, '佩可莉姆', '咻咻♪\\n咚咚啪啪♪', 1, 0, '');
insert into login_bonus_message_data values (120, 80003, 1, 1, 0, 0, 105901, '可可萝', '咻咻，\\n咚咚啪啪。', 1, 0, '');
insert into login_bonus_message_data values (121, 80003, 1, 1, 0, 0, 105901, '可可萝', '来，凯露小姐也一起来\\n咚咚啪啪吧。', 2, 0, '');
insert into login_bonus_message_data values (122, 80003, 2, 1, 0, 0, 106001, '凯露', '诶？等一下，\\n你们突然干什么呢？', 1, 0, '');
insert into login_bonus_message_data values (123, 80003, 2, 1, 0, 0, 106001, '凯露', '咚咚啪啪是什么？\\n用我也能理解的方式\\n说明一下呀！', 2, 0, '');
insert into login_bonus_message_data values (124, 80003, 0, 1, 0, 0, 105801, '佩可莉姆', '小凯露，其实是这样的！\\n一个对我们来说非常重要的节日\\n马上就要到了——', 2, 0, '');
insert into login_bonus_message_data values (125, 80003, 0, 1, 0, 0, 105801, '佩可莉姆', '那就是“公主连结！\\nRe:Dive”\\n2.5周年纪念日哦！\\n超棒的对吧☆', 3, 0, '');
insert into login_bonus_message_data values (126, 80003, 1, 1, 0, 0, 105901, '可可萝', '所以，为了那一天，\\n我们现在就要先炒热气氛。', 3, 0, '');
insert into login_bonus_message_data values (127, 80003, 2, 1, 0, 0, 106001, '凯露', '啊，说起来还真是，\\n不过就算是快到那个时候了，\\n也还有一段时间吧，\\n会不会太心急了？', 3, 0, '');
insert into login_bonus_message_data values (128, 80003, 1, 1, 0, 0, 105901, '可可萝', '不，凯露小姐，\\n这种庆典就是要从准备阶段开始\\n好好享受。对吧，佩可莉姆小姐。', 4, 0, '');
insert into login_bonus_message_data values (129, 80003, 0, 1, 0, 0, 105801, '佩可莉姆', '就是这样♪\u3000综上所述！\\n倒计时开始了哦！\\n大家一起热闹地庆祝2.5周年吧☆', 4, 0, '');
insert into login_bonus_message_data values (130, 80003, 2, 1, 0, 0, 106001, '凯露', '咚、咚咚啪啪～\\n你们让我都说些什么呢！\\n真是的，完全兴奋过头了啊。', 4, 0, '');
insert into login_bonus_message_data values (131, 80003, 1, 1, 0, 0, 105901, '可可萝', '呵呵。凯露小姐似乎也很期待呢。\\n那么，主人。在重要的纪念日到来之前，\\n就请好好地期待吧。', 5, 0, '');
insert into login_bonus_message_data values (132, 80003, 0, 2, 0, 0, 106001, '凯露', '说是要热闹地庆祝纪念日，\\n但到底要做点什么好呢？\\n我不太擅长做这些……', 5, 0, '');
insert into login_bonus_message_data values (133, 80003, 1, 2, 0, 0, 190801, '花凛', '哎呀，凯露小姐\\n怎么了？\\n看你似乎有什么烦恼。', 1, 0, '');
insert into login_bonus_message_data values (134, 80003, 0, 2, 0, 0, 106001, '凯露', '呃……这不是花凛嘛。\\n我没事！', 6, 0, '');
insert into login_bonus_message_data values (135, 80003, 1, 2, 0, 0, 190801, '花凛', '是这样吗？\\n毕竟是凯露小姐，\\n我还以为是在烦恼2.5周年要怎么庆祝呢……', 2, 0, '');
insert into login_bonus_message_data values (136, 80003, 0, 2, 0, 0, 106001, '凯露', '你这不是知道的嘛！？\\n不、不是的，不是这样的！\\n我可没有为这种事烦恼哦？', 7, 0, '');
insert into login_bonus_message_data values (137, 80003, 1, 2, 0, 0, 190801, '花凛', '呵呵……\\n这种时候，将真实的想法\\n直接说出口不是比较好吗？', 3, 0, '');
insert into login_bonus_message_data values (138, 80003, 0, 2, 0, 0, 106001, '凯露', '自己的真实想法啊，\\n这不就是最难的吗……\\n其实对我来说，纪念日怎么过都行。', 8, 0, '');
insert into login_bonus_message_data values (139, 80003, 0, 2, 0, 0, 106001, '凯露', '不过，佩可莉姆和可萝仔\\n看上去都这么开心……\\n所以我就在想，偶尔像这样\\n狂欢一下也不错吧。', 9, 0, '');
insert into login_bonus_message_data values (140, 80003, 1, 2, 0, 0, 190801, '花凛', '原来如此原来如此～\\n也就是说，凯露小姐由衷地\\n期待着【美食殿堂】2.5周年的\\n庆祝活动呢！', 4, 0, '');
insert into login_bonus_message_data values (141, 80003, 0, 2, 0, 0, 106001, '凯露', '哈！？\\n你是怎么理解的啊！\\n我才没有期待！', 10, 0, '');
insert into login_bonus_message_data values (142, 80003, 1, 2, 0, 0, 190801, '花凛', '凯露小姐内心的想法\\n都传达给大家了吧？\\n我也很期待2.5周年！\\n以上就是花凛的报道！', 5, 0, '');
insert into login_bonus_message_data values (143, 80003, 0, 2, 0, 0, 106001, '凯露', '内心的想法是什么啊！？\\n不要擅自曲解\\n别人说的话！\\n你这个混账四眼！', 11, 0, '');
insert into login_bonus_message_data values (144, 80003, 0, 3, 0, 0, 105901, '可可萝', '佩可莉姆小姐，马上\\n就要到纪念日了。\\n这样的日子还真是令人感慨万分。', 6, 0, '');
insert into login_bonus_message_data values (145, 80003, 1, 3, 0, 0, 105801, '佩可莉姆', '会让人想起各种各样的回忆呢！\\n想起了一大堆开心的事♪', 5, 0, '');
insert into login_bonus_message_data values (146, 80003, 0, 3, 0, 0, 105901, '可可萝', '是的，没错。\\n我也听主人说过，\\n除了【美食殿堂】的活动之外，\\n还有很多其他的经历呢。', 7, 0, '');
insert into login_bonus_message_data values (147, 80003, 0, 3, 0, 0, 105901, '可可萝', '我记得……好像是在兰德索尔\\n遇见了传闻中的魔法少女之类的。', 8, 0, '');
insert into login_bonus_message_data values (148, 80003, 1, 3, 0, 0, 105801, '佩可莉姆', '魔法少女，就是那个美味\\n又富含营养的热门商品\\n“魔法少女香肠”盒子上\\n画着的女孩吗！？', 6, 0, '');
insert into login_bonus_message_data values (149, 80003, 1, 3, 0, 0, 105801, '佩可莉姆', '那个香肠很美味的哦♪\\n我也吃了很多！', 7, 0, '');
insert into login_bonus_message_data values (150, 80003, 0, 3, 0, 0, 105901, '可可萝', '还有，牧场建了个\\n非常不错的温泉……', 9, 0, '');
insert into login_bonus_message_data values (151, 80003, 1, 3, 0, 0, 105801, '佩可莉姆', '牧场吗！？\u3000泡着温泉吃奶酪\\n也别有一番风味呢♪\u3000光是想想\\n就要流口水了！\\n超棒的对吧☆', 8, 0, '');
insert into login_bonus_message_data values (152, 80003, 0, 3, 0, 0, 105901, '可可萝', '佩可莉姆小姐\\n刚说完就流口水了……\\n我现在帮你擦掉。擦擦……', 10, 0, '');
insert into login_bonus_message_data values (153, 80003, 1, 3, 0, 0, 105801, '佩可莉姆', '诶嘿嘿，谢谢你，\\n小可萝！', 9, 0, '');
insert into login_bonus_message_data values (154, 80003, 0, 3, 0, 0, 105901, '可可萝', '话说回来，主人\\n作为【美食殿堂】的一员，遇到了\\n各种各样的美食呢。\\n真令人佩服。', 11, 0, '');
insert into login_bonus_message_data values (155, 80003, 1, 3, 0, 0, 105801, '佩可莉姆', '接下来也要多多去冒险，\\n吃遍各种美食哦！', 10, 0, '');
insert into login_bonus_message_data values (156, 80003, 0, 4, 0, 0, 105801, '佩可莉姆', '2.5周年倒计时♪小凯露小凯露！\\n好兴奋呀☆', 11, 0, '');
insert into login_bonus_message_data values (157, 80003, 1, 4, 0, 0, 106001, '凯露', '啊啊真是的，吵死了～\\n还没那么快到吧？\\n稍微冷静一点啊。', 12, 0, '');
insert into login_bonus_message_data values (158, 80003, 0, 4, 0, 0, 105801, '佩可莉姆', '小凯露最近\\n不是也很兴奋吗～\\n刚才也心情很好地\\n哼歌了吧？', 12, 0, '');
insert into login_bonus_message_data values (159, 80003, 1, 4, 0, 0, 106001, '凯露', '什……你、你听到了吗！？\\n不对，我才没哼呢！？\\n你再说些莫名其妙的话，\\n小心我宰了你哦！？', 13, 0, '');
insert into login_bonus_message_data values (160, 80003, 0, 4, 0, 0, 105801, '佩可莉姆', '诶嘿嘿♪\\n我越来越喜欢最近的小凯露了♪\\n变得非常积极了呢！', 13, 0, '');
insert into login_bonus_message_data values (161, 80003, 1, 4, 0, 0, 106001, '凯露', '积极？\\n你在说什么呀？', 14, 0, '');
insert into login_bonus_message_data values (162, 80003, 0, 4, 0, 0, 105801, '佩可莉姆', '又来了♪\\n你已经忘记要成为偶像的事了吗？', 14, 0, '');
insert into login_bonus_message_data values (163, 80003, 0, 4, 0, 0, 105801, '佩可莉姆', '在缪斯镇的时候，\\n还凯露凯露呢☆', 15, 0, '');
insert into login_bonus_message_data values (164, 80003, 1, 4, 0, 0, 106001, '凯露', '啊！？\u3000才才才不是！\\n那只是被操控了，\\n我才没有想要成为什么偶像呢！', 15, 0, '');
insert into login_bonus_message_data values (165, 80003, 0, 4, 0, 0, 105801, '佩可莉姆', '真的是真的吗？\\n我倒是觉得小凯露\\n兴致满满呢～', 16, 0, '');
insert into login_bonus_message_data values (166, 80003, 1, 4, 0, 0, 106001, '凯露', '虽然感觉是不坏啦……呃，\\n所、所以说，我并不想成为偶像啦！\\n这都让我想起了什么事啊！？', 16, 0, '');
insert into login_bonus_message_data values (167, 80003, 1, 4, 0, 0, 106001, '凯露', '啊啊……不行了……\\n只能宰掉了……\\n在2.5周年到来之前，\\n连同记忆一起抹去！', 17, 0, '');
insert into login_bonus_message_data values (168, 80003, 0, 5, 0, 0, 106001, '凯露', '距离2.5周年还有10天……\\n诶～\\n居然还挺快呢？', 18, 0, '');
insert into login_bonus_message_data values (169, 80003, 1, 5, 0, 0, 105901, '可可萝', '是啊……\\n为了那一天的到来，\\n还有许多要做的事，\\n必须绷紧神经才行！', 12, 0, '');
insert into login_bonus_message_data values (170, 80003, 0, 5, 0, 0, 106001, '凯露', '干劲十足呢，可萝仔……\\n这么拼命会很累的哦？\\n放松一点吧？', 19, 0, '');
insert into login_bonus_message_data values (171, 80003, 1, 5, 0, 0, 105901, '可可萝', '凯露小姐……\\n谢谢您。\\n凯露小姐真的\\n非常温柔。', 13, 0, '');
insert into login_bonus_message_data values (172, 80003, 0, 5, 0, 0, 106001, '凯露', '在、在说什么\\n莫名其妙的话呢……\\n我才不温柔呢。', 20, 0, '');
insert into login_bonus_message_data values (173, 80003, 1, 5, 0, 0, 105901, '可可萝', '没有这回事。\\n那个，其实我\\n有一件事\\n想拜托凯露小姐。', 14, 0, '');
insert into login_bonus_message_data values (174, 80003, 0, 5, 0, 0, 106001, '凯露', '拜托我？真稀奇啊，\\n可萝仔居然会说这种话。\\n算了，只要是我能做到的事，\\n倒也没关系。', 21, 0, '');
insert into login_bonus_message_data values (175, 80003, 1, 5, 0, 0, 105901, '可可萝', '非常感谢。\\n其实，我想为纪念日\\n提前准备一种叫\\n“即兴表演”的东西。', 15, 0, '');
insert into login_bonus_message_data values (176, 80003, 0, 5, 0, 0, 106001, '凯露', '即兴表演？', 22, 0, '');
insert into login_bonus_message_data values (177, 80003, 1, 5, 0, 0, 105901, '可可萝', '是的。以凯露凯露☆作为\\n参考，我想到了可萝可萝☆这种\\n打招呼的方式，\\n但不知道配合什么动作好……', 16, 0, '');
insert into login_bonus_message_data values (178, 80003, 0, 5, 0, 0, 106001, '凯露', '亏我听到表扬还得意了一下，\\n真是白高兴了！\\n别开玩笑了别开玩笑了，\\n别～开～玩～笑～了！', 23, 0, '');
insert into login_bonus_message_data values (179, 80003, 0, 6, 0, 0, 105801, '佩可莉姆', '还有9天！\u3000马上就到了哦♪\\n诶嘿嘿，太期待太期待了，\\n吃饭都特别香呢☆', 17, 0, '');
insert into login_bonus_message_data values (180, 80003, 2, 6, 0, 0, 106001, '凯露', '什么\\n吃饭特别香☆啊！\\n你也吃得太多了！\\n小心没法迎接纪念日哦！？', 24, 0, '');
insert into login_bonus_message_data values (181, 80003, 1, 6, 0, 0, 105901, '可可萝', '没事的，凯露小姐。\\n毕竟我们的冒险之旅\\n也是美食之旅。', 17, 0, '');
insert into login_bonus_message_data values (182, 80003, 0, 6, 0, 0, 105801, '佩可莉姆', '不愧是小可萝，\\n说得真好！\\n对，我们\\n【美食殿堂】的活动目的——', 18, 0, '');
insert into login_bonus_message_data values (183, 80003, 2, 6, 0, 0, 106001, '凯露', '就是大家一起享受吃饭，\\n对吧？\\n毕竟边走边吃了那么多，\\n我早就知道了。', 25, 0, '');
insert into login_bonus_message_data values (184, 80003, 1, 6, 0, 0, 105901, '可可萝', '是的，就是这样♪\\n话说回来，我们\\n真的是边走边吃了\\n好多东西呢……', 18, 0, '');
insert into login_bonus_message_data values (185, 80003, 2, 6, 0, 0, 106001, '凯露', '对，没错……\\n虽然全身是毒的假龙，\\n还有恐龙好像没能抓到……\\n鳄鱼龙……不，鳄鱼魔物之类的也是。', 26, 0, '');
insert into login_bonus_message_data values (186, 80003, 2, 6, 0, 0, 106001, '凯露', '而且，我们最后\\n还和真正的龙\\n成为对手了呢。', 27, 0, '');
insert into login_bonus_message_data values (187, 80003, 2, 6, 0, 0, 106001, '凯露', '那条龙真是\\n强到令人难以置信……果然还是\\n要认真地准备好作战计划\\n才行呢。', 28, 0, '');
insert into login_bonus_message_data values (188, 80003, 0, 6, 0, 0, 105801, '佩可莉姆', '诶嘿嘿☆\\n小凯露记住了\\n各种各样的事情呢，\\n我好开心♪', 19, 0, '');
insert into login_bonus_message_data values (189, 80003, 1, 6, 0, 0, 105901, '可可萝', '我也记得很清楚哦，\\n主人也一定是这样♪', 19, 0, '');
insert into login_bonus_message_data values (190, 80003, 2, 6, 0, 0, 106001, '凯露', '这是当然的吧！\\n怎么会忘掉，净是让我吃那种\\n乱七八糟的东西！\\n怎么可能会忘记啊……', 29, 0, '');
insert into login_bonus_message_data values (191, 80003, 0, 7, 0, 0, 106001, '凯露', '我说，等等，等一下！？\\n花凛说，希望我们\\n出演2.5周年纪念\\n的现场直播！', 30, 0, '');
insert into login_bonus_message_data values (192, 80003, 0, 7, 0, 0, 106001, '凯露', '为什么突然说出\\n这么重要的事！？\\n我都没听说有这种事啊！？', 31, 0, '');
insert into login_bonus_message_data values (193, 80003, 0, 7, 0, 0, 106001, '凯露', '会被很多人看见吧？\\n为什么我要做这种事……', 32, 0, '');
insert into login_bonus_message_data values (194, 80003, 0, 7, 0, 0, 106001, '凯露', '啊——\\n啊——\\n这样发声没问题吧？', 33, 0, '');
insert into login_bonus_message_data values (195, 80003, 0, 7, 0, 0, 106001, '凯露', '或许会听不清呢……\\n还是稍微开朗一点会比较好，\\n唔……这种感觉？', 34, 0, '');
insert into login_bonus_message_data values (196, 80003, 0, 7, 0, 0, 106001, '凯露', '你好呀☆', 35, 0, '');
insert into login_bonus_message_data values (197, 80003, 0, 7, 0, 0, 106001, '凯露', '……\\n不，这个不行。\\n还是和平时一样最好，嗯。', 36, 0, '');
insert into login_bonus_message_data values (198, 80003, 0, 7, 0, 0, 106001, '凯露', '真是的，纪念日的现场直播什么的，\\n这不是责任超级重吗……\\n如果哪里失误的话……', 37, 0, '');
insert into login_bonus_message_data values (199, 80003, 0, 7, 0, 0, 106001, '凯露', '怎、怎怎、怎么办！？\\n开始紧张了！', 38, 0, '');
insert into login_bonus_message_data values (200, 80003, 0, 8, 0, 0, 105901, '可可萝', '主人，我和佩可莉姆小姐\\n还有凯露小姐都有一同\\n出演2.5周年现场直播\\n的重要任务。', 20, 0, '');
insert into login_bonus_message_data values (201, 80003, 0, 8, 0, 0, 105901, '可可萝', '向大家传达\\n“公主连结！\\nRe:Dive”的魅力\\n的重要任务。', 21, 0, '');
insert into login_bonus_message_data values (202, 80003, 0, 8, 0, 0, 105901, '可可萝', '我会\\n全心全意配合\\n现场直播做好准备。', 22, 0, '');
insert into login_bonus_message_data values (203, 80003, 0, 8, 0, 0, 105901, '可可萝', '可是，说不定\\n我也会念错台词\\n或是搞错流程……', 23, 0, '');
insert into login_bonus_message_data values (204, 80003, 0, 8, 0, 0, 105901, '可可萝', '为了避免这些情况，\\n要好好练习才行。\\n首先从这里开始……', 24, 0, '');
insert into login_bonus_message_data values (205, 80003, 0, 8, 0, 0, 105901, '可可萝', '你好呀☆', 25, 0, '');
insert into login_bonus_message_data values (206, 80003, 0, 8, 0, 0, 105901, '可可萝', '刚才看见\\n凯露小姐在练习的样子，\\n我也想试一试……\\n您觉得如何？', 26, 0, '');
insert into login_bonus_message_data values (207, 80003, 0, 8, 0, 0, 105901, '可可萝', '感觉不错吗？\\n呵呵，谢谢。\\n对我来说，主人温暖的话语\\n让我备受鼓舞。', 27, 0, '');
insert into login_bonus_message_data values (208, 80003, 0, 8, 0, 0, 105901, '可可萝', '为了顺利完成这份重要的任务，\\n让主人能迎来美妙的2.5周年……\\n我会竭尽全力的。', 28, 0, '');
insert into login_bonus_message_data values (209, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '你好呀☆', 20, 0, '');
insert into login_bonus_message_data values (210, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '唔，刚才的\\n感觉有些不对呢。\\n或许有点太僵硬了。', 21, 0, '');
insert into login_bonus_message_data values (211, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '还有6天就到2.5周年了吗……', 22, 0, '');
insert into login_bonus_message_data values (212, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '一想到这段时光\\n是“你好呀”的历史，\\n我就干劲十足呢！\\n超棒的对吧☆', 23, 0, '');
insert into login_bonus_message_data values (213, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '为了在现场直播\\n给大家送上最棒的“你好呀☆”\\n我要努力才行！\\n那就再来一次……', 24, 0, '');
insert into login_bonus_message_data values (214, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '你好呀☆', 25, 0, '');
insert into login_bonus_message_data values (215, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '唔唔，怎么会这样。\\n还是感觉哪里不对……\\n难道是因为\\n肚子太饿了吗？', 26, 0, '');
insert into login_bonus_message_data values (216, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '虽然刚刚才吃过，\\n但肚子饿的话就没法喊出\\n“好的你好呀☆”了！', 27, 0, '');
insert into login_bonus_message_data values (217, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '既然都决定了，那就约上小可萝\\n和小凯露一起\\n去吃饭吧！\\n事不宜迟！', 28, 0, '');
insert into login_bonus_message_data values (218, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '啊，你们俩来得正好！\\n你好呀☆……啊啊！\\n刚才、刚才的感觉就对了♪', 29, 0, '');
insert into login_bonus_message_data values (219, 80003, 0, 9, 0, 0, 105801, '佩可莉姆', '原来如此，无论什么时候，\\n自然状态都是最好的！\\n就按这个状态加油吧！\\n我会努力准备现场直播的♪', 30, 0, '');
insert into login_bonus_message_data values (220, 80003, 0, 10, 0, 0, 105801, '佩可莉姆', '虽然距离2.5周年还有５天，\\n但在那之前，现场直播马上就要开始了！\\n小可萝\\n准备得怎么样了？', 31, 0, '');
insert into login_bonus_message_data values (221, 80003, 1, 10, 0, 0, 105901, '可可萝', '好的。我已经\\n准备得非常充足了，\\n万无一失。', 29, 0, '');
insert into login_bonus_message_data values (222, 80003, 0, 10, 0, 0, 105801, '佩可莉姆', '哦哦～感觉非常有自信！\\n会是一场很棒的现场直播吧☆\\n咦？有没有觉得这附近\\n在摇晃？', 32, 0, '');
insert into login_bonus_message_data values (223, 80003, 2, 10, 0, 0, 106001, '凯露', '……', 39, 0, '');
insert into login_bonus_message_data values (224, 80003, 1, 10, 0, 0, 105901, '可可萝', '凯露小姐？\\n您是感冒了吗？\\n抖得这么厉害……', 30, 0, '');
insert into login_bonus_message_data values (225, 80003, 2, 10, 0, 0, 106001, '凯露', '才才才才不是感冒！\\n这这这这只是\\n过过过于期待现场直播，\\n兴兴兴兴奋得不得了而已！', 40, 0, '');
insert into login_bonus_message_data values (226, 80003, 0, 10, 0, 0, 105801, '佩可莉姆', '小凯露，你没事吧！？\\n对了，请喝这个吧！', 33, 0, '');
insert into login_bonus_message_data values (227, 80003, 2, 10, 0, 0, 106001, '凯露', '很很很会做事嘛，谢谢。\\n咕咚、咕……噗哈！？\\n等等，你给我喝的是什么！？\\n好辣！\u3000好苦！？\u3000好甜！？', 41, 0, '');
insert into login_bonus_message_data values (228, 80003, 0, 10, 0, 0, 105801, '佩可莉姆', '这是用魔物的精华和药草\\n混合了其他各种材料\\n特制的营养饮料！', 34, 0, '');
insert into login_bonus_message_data values (229, 80003, 0, 10, 0, 0, 105801, '佩可莉姆', '只要喝下这个，\\n身体就会变得暖暖的，\\n会精神满满的哦♪', 35, 0, '');
insert into login_bonus_message_data values (230, 80003, 2, 10, 0, 0, 106001, '凯露', '这个笨蛋莉姆！\\n我说过不是感冒了吧！？\\n不要趁乱\\n让我喝下这么可怕的东西！', 42, 0, '');
insert into login_bonus_message_data values (231, 80003, 1, 10, 0, 0, 105901, '可可萝', '凯露小姐，\\n您的颤抖已经停下来了呢。\\n真是太好了……\\n我还很担心呢。', 31, 0, '');
insert into login_bonus_message_data values (232, 80003, 2, 10, 0, 0, 106001, '凯露', '咦？啊啊，真的呢……呃，\\n所以我都说\\n不是感冒了……\\n算了，事到如今也无所谓了。', 43, 0, '');
insert into login_bonus_message_data values (233, 80003, 0, 10, 0, 0, 105801, '佩可莉姆', '诶嘿嘿♪平日里的\\n小凯露又回来了，\\n现场直播应该会很精彩吧！\\n我现在就开始期待了☆', 36, 0, '');
insert into login_bonus_message_data values (234, 80003, 0, 11, 0, 0, 190801, '花凛', '兰德索尔的各位朋友，大家好。\\n我是现场直播的会场负责人，\\n【公会管理协会】的花凛。', 6, 0, '');
insert into login_bonus_message_data values (235, 80003, 0, 11, 0, 0, 190801, '花凛', '为了即将开始的现场直播，\\n【美食殿堂】的各位需要进行\\n最后的调整，因此暂时离席。', 7, 0, '');
insert into login_bonus_message_data values (236, 80003, 0, 11, 0, 0, 190801, '花凛', '因为不能打扰到\\n正在努力准备的三个人，\\n还望各位见谅哦。', 8, 0, '');
insert into login_bonus_message_data values (237, 80003, 0, 11, 0, 0, 190801, '花凛', '所以呢，从今天开始，\\n将由我来介绍\\n【美食殿堂】的几位成员的情况。', 9, 0, '');
insert into login_bonus_message_data values (238, 80003, 0, 11, 0, 0, 190801, '花凛', '首先是佩可莉姆……\\n她好像在吃\\n大量的饭团。\\n那个……营养很重要呢。', 10, 0, '');
insert into login_bonus_message_data values (239, 80003, 0, 11, 0, 0, 190801, '花凛', '接下来是可可萝小姐，\\n她正在进行发声练习。', 11, 0, '');
insert into login_bonus_message_data values (240, 80003, 0, 11, 0, 0, 190801, '花凛', '看到她拼尽全力张开小嘴的模样，\\n我都想为她加油了呢。', 12, 0, '');
insert into login_bonus_message_data values (241, 80003, 0, 11, 0, 0, 190801, '花凛', '然后，凯露小姐是……\\n这还真是……光明正大呢。\\n什么都没做，就只是站着不动……', 13, 0, '');
insert into login_bonus_message_data values (242, 80003, 0, 11, 0, 0, 190801, '花凛', '咦？\\n难道是紧张到失去意识了？', 14, 0, '');
insert into login_bonus_message_data values (243, 80003, 0, 11, 0, 0, 190801, '花凛', '嗯……\\n【美食殿堂】的各位\\n似乎都干劲十足呢！', 15, 0, '');
insert into login_bonus_message_data values (244, 80003, 0, 11, 0, 0, 190801, '花凛', '她们三个人都在\\n为了做好现场直播\\n而拼尽全力呢，\\n敬请期待哦。', 16, 0, '');
insert into login_bonus_message_data values (245, 80003, 0, 11, 0, 0, 190801, '花凛', '那么，\\n我们明天再见♪', 17, 0, '');
insert into login_bonus_message_data values (246, 80003, 0, 12, 0, 0, 106001, '凯露', '距离2.5周年还有3天！\\n然后明天就是现场直播了！\\n感觉终于要开始了……', 44, 0, '');
insert into login_bonus_message_data values (247, 80003, 2, 12, 0, 0, 105801, '佩可莉姆', '三个人一起练习了那～么久，\\n一定没问题的☆', 37, 0, '');
insert into login_bonus_message_data values (248, 80003, 1, 12, 0, 0, 105901, '可可萝', '听到佩可莉姆小姐\\n说没问题之后，\\n感觉非常可靠呢。', 32, 0, '');
insert into login_bonus_message_data values (249, 80003, 0, 12, 0, 0, 106001, '凯露', '可萝仔，不能过于相信她哦。\\n这家伙只是什么都\\n没有考虑过而已。', 45, 0, '');
insert into login_bonus_message_data values (250, 80003, 2, 12, 0, 0, 105801, '佩可莉姆', '好过分啊，小凯露！', 38, 0, '');
insert into login_bonus_message_data values (251, 80003, 1, 12, 0, 0, 105901, '可可萝', '呵呵。两位\\n都和平常一样呢，\\n我放心了。', 33, 0, '');
insert into login_bonus_message_data values (252, 80003, 2, 12, 0, 0, 105801, '佩可莉姆', '是的☆\\n无论是现场直播还是其他活动，\\n我都要全力以赴，用自己的方式\\n使劲冲就对了！', 39, 0, '');
insert into login_bonus_message_data values (253, 80003, 0, 12, 0, 0, 106001, '凯露', '是啊。既然是可喜可贺的事情，\\n而且都走到这一步了，\\n那就必须\\n尽情享受才行！', 46, 0, '');
insert into login_bonus_message_data values (254, 80003, 1, 12, 0, 0, 105901, '可可萝', '我也是，心情\\n比平时还要激动，\\n我会努力将自己心中的这份感受\\n传递给大家！', 34, 0, '');
insert into login_bonus_message_data values (255, 80003, 2, 12, 0, 0, 105801, '佩可莉姆', '那么，我们走吧！\\n明天的现场直播，\\n我们必须成功☆', 40, 0, '');
insert into login_bonus_message_data values (256, 80003, 0, 13, 0, 0, 105801, '佩可莉姆', '那个，一开始要说的是……咦？\\n小凯露，\\n我要说什么来着？', 41, 0, '');
insert into login_bonus_message_data values (257, 80003, 2, 13, 0, 0, 106001, '凯露', '哈！？\\n怎么突然就忘记了！？\\n话说，你的台词本呢！？', 47, 0, '');
insert into login_bonus_message_data values (258, 80003, 0, 13, 0, 0, 105801, '佩可莉姆', '我忘记带了☆', 42, 0, '');
insert into login_bonus_message_data values (259, 80003, 2, 13, 0, 0, 106001, '凯露', '我忘记带了☆\\n你以为这么说就好了吗！？\\n来，我带了两本，\\n你就用这本吧！', 48, 0, '');
insert into login_bonus_message_data values (260, 80003, 1, 13, 0, 0, 105901, '可可萝', '麦克风原来是在\\n这么高的位置呢！\\n只要把背挺直，应该就能……\\n唔、唔嗯！', 35, 0, '');
insert into login_bonus_message_data values (261, 80003, 2, 13, 0, 0, 106001, '凯露', '啊啊真是的，\\n降下来一点就好了吧！？\\n这样可以吗？\\n真是让人操碎了心……', 49, 0, '');
insert into login_bonus_message_data values (262, 80003, 0, 13, 0, 0, 105801, '佩可莉姆', '咦？\\n小凯露，你后面的头发\\n翘起来了哦？', 43, 0, '');
insert into login_bonus_message_data values (263, 80003, 2, 13, 0, 0, 106001, '凯露', '诶？不会吧！？\\n我明明仔细确认过的！\\n哪里哪里！？', 50, 0, '');
insert into login_bonus_message_data values (264, 80003, 1, 13, 0, 0, 105901, '可可萝', '凯露小姐，请您\\n不要动。我现在用梳子……\\n好了，弄好了。', 36, 0, '');
insert into login_bonus_message_data values (265, 80003, 2, 13, 0, 0, 106001, '凯露', '谢、谢谢……唉，现场直播\\n马上就要正式开始了，\\n现在可不是做这种事的时候。', 51, 0, '');
insert into login_bonus_message_data values (266, 80003, 1, 13, 0, 0, 105901, '可可萝', '是的，时间不多了。\\n不过，慌慌张张动来动去\\n的这段时间\\n似乎也挺开心的♪', 37, 0, '');
insert into login_bonus_message_data values (267, 80003, 2, 13, 0, 0, 106001, '凯露', '可萝仔，你……呃，\\n不对！\\n现在可没有时间\\n慢慢感动了啊！？', 52, 0, '');
insert into login_bonus_message_data values (268, 80003, 0, 13, 0, 0, 105801, '佩可莉姆', '啊哈哈♪\\n小凯露的动作\\n真有趣♪\\n超棒的☆', 44, 0, '');
insert into login_bonus_message_data values (269, 80003, 1, 13, 0, 0, 105901, '可可萝', '呵呵，\\n我现在十分确信，\\n这一定会成为很有意思的现场直播。', 38, 0, '');
insert into login_bonus_message_data values (270, 80003, 0, 13, 0, 0, 105801, '佩可莉姆', '绝对绝对不会错的！\\n为观看直播的朋友们\\n带去欢笑的\\n时光吧！', 45, 0, '');
insert into login_bonus_message_data values (271, 80003, 2, 13, 0, 0, 106001, '凯露', '那是当然的！\\n毕竟，为了让观看直播的\\n所有人都能觉得有趣，\\n我们可是准备了那么久啊！', 53, 0, '');
insert into login_bonus_message_data values (272, 80003, 0, 13, 0, 0, 105801, '佩可莉姆', '那么，\\n纪念日之前的现场直播！\\n请大家好好期待吧☆', 46, 0, '');
insert into login_bonus_message_data values (273, 80003, 0, 14, 0, 0, 190801, '花凛', '大家好，\\n我是【公会管理协会】的花凛。', 18, 0, '');
insert into login_bonus_message_data values (274, 80003, 0, 14, 0, 0, 190801, '花凛', '各位觉得\\n昨天的现场直播怎么样呢？', 19, 0, '');
insert into login_bonus_message_data values (275, 80003, 0, 14, 0, 0, 190801, '花凛', '我想，应该是收到了\\n许多笑容与欢乐，\\n还有惊吓吧。', 20, 0, '');
insert into login_bonus_message_data values (276, 80003, 0, 14, 0, 0, 190801, '花凛', '然后，明天就终于\\n要迎来2.5周年的纪念日——\\n我们期待已久的日子了。', 21, 0, '');
insert into login_bonus_message_data values (277, 80003, 0, 14, 0, 0, 190801, '花凛', '【美食殿堂】的各位也在\\n紧张地做着各种准备哦。', 22, 0, '');
insert into login_bonus_message_data values (278, 80003, 0, 14, 0, 0, 190801, '花凛', '我们【公会管理协会】也希望\\n能以健全的体制\\n去协助她们。', 23, 0, '');
insert into login_bonus_message_data values (279, 80003, 0, 14, 0, 0, 190801, '花凛', '呵呵，真让人期待呢，\\n不仅仅是作为【公会管理协会】的职员，\\n作为我个人也是……', 24, 0, '');
insert into login_bonus_message_data values (280, 80003, 0, 14, 0, 0, 190801, '花凛', '我由衷地期待\\n这个纪念日的到来，\\n也为此感到十分幸福。', 25, 0, '');
insert into login_bonus_message_data values (281, 80003, 0, 14, 0, 0, 190801, '花凛', '【美食殿堂】的各位\\n肯定比我还要更加激动吧。', 26, 0, '');
insert into login_bonus_message_data values (282, 80003, 0, 14, 0, 0, 190801, '花凛', '那么，\\n请期待从明天起开始举办的\\n2.5周年纪念活动哦♪', 27, 0, '');
insert into login_bonus_message_data values (283, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '准备好了吗？\\n要上了哦！', 47, 0, '');
insert into login_bonus_message_data values (284, 80003, 2, 15, 0, 0, 106001, '凯露', '祝贺！', 54, 0, '');
insert into login_bonus_message_data values (285, 80003, 1, 15, 0, 0, 105901, '可可萝', '2.5周年！', 39, 0, '');
insert into login_bonus_message_data values (286, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '纪念日快乐☆', 48, 0, '');
insert into login_bonus_message_data values (287, 80003, 2, 15, 0, 0, 106001, '凯露', '前不久\\n都还说没那么快呢，\\n但真是一眨眼就到了。', 55, 0, '');
insert into login_bonus_message_data values (288, 80003, 1, 15, 0, 0, 105901, '可可萝', '这就是……所谓的\\n光阴似箭呢。\\n不过，能顺利迎来今天\\n真是太好了。', 40, 0, '');
insert into login_bonus_message_data values (289, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '小可萝！\u3000小凯露！\\n现在就冷静下来\\n还太早了！\\n接下来才要正式开始热闹地庆祝哦☆', 49, 0, '');
insert into login_bonus_message_data values (290, 80003, 2, 15, 0, 0, 106001, '凯露', '你真的总是在\\n全力以赴呢，\\n不过也对，毕竟是纪念日，\\n就来热闹一下吧！', 56, 0, '');
insert into login_bonus_message_data values (291, 80003, 1, 15, 0, 0, 105901, '可可萝', '嗯，我也要\\n全力以赴了！\\n主人，来吧，\\n请握住我的手♪', 41, 0, '');
insert into login_bonus_message_data values (292, 80003, 2, 15, 0, 0, 106001, '凯露', '你和可萝仔都不要因为太兴奋\\n而摔倒哦？\\n没办法了，那我也\\n牵住你的手吧。', 57, 0, '');
insert into login_bonus_message_data values (293, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '啊！\u3000你们俩太狡猾了！\\n我也要抱紧♪', 50, 0, '');
insert into login_bonus_message_data values (294, 80003, 2, 15, 0, 0, 106001, '凯露', '等等，佩可莉姆！\\n你粘得太近了！', 58, 0, '');
insert into login_bonus_message_data values (295, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '因为是纪念日嘛，\\n没关系没关系♪\\n超棒的☆', 51, 0, '');
insert into login_bonus_message_data values (296, 80003, 2, 15, 0, 0, 106001, '凯露', '在说什么莫名其妙的话啊！', 59, 0, '');
insert into login_bonus_message_data values (297, 80003, 1, 15, 0, 0, 105901, '可可萝', '呵呵。在这可喜可贺的日子里，\\n到处都是欢声笑语呢。\\n主人……您觉得如何？', 42, 0, '');
insert into login_bonus_message_data values (298, 80003, 1, 15, 0, 0, 105901, '可可萝', '如果能让您开心，\\n我也会非常非常幸福的。', 43, 0, '');
insert into login_bonus_message_data values (299, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '来，尽情享受2.5周年吧☆\\n有好多好多想吃的食物，\\n还有好多好多想做的事呢！', 52, 0, '');
insert into login_bonus_message_data values (300, 80003, 2, 15, 0, 0, 106001, '凯露', '我知道了，知道了啦。\\n不要拉我了！\\n不用那么抓着我，\\n我会好好跟着的。', 60, 0, '');
insert into login_bonus_message_data values (301, 80003, 1, 15, 0, 0, 105901, '可可萝', '佩可莉姆小姐……凯露小姐……\\n主人……让我们共同前行\\n继续踏上旅程吧！', 44, 0, '');
insert into login_bonus_message_data values (302, 80003, 0, 15, 0, 0, 105801, '佩可莉姆', '好！\u3000那么，就来个2.5周年\\n吃遍天下之旅吧！\\n然后，再朝着未来进发！', 53, 0, '');
insert into login_bonus_message_data values (303, 80003, 0, 15, 0, 0, 105801, '佩可莉姆·可可萝·凯露', '2.5周年，\\n感谢大家的支持！', 54, 1, '105901,45,106001,61');
